import type { LLMClient } from './types.js';

export class LLMRouter {
  private readonly clients = new Map<string, LLMClient>();

  constructor(private readonly cfg: ToaaConfig) {
    for (const [name, p] of Object.entries(cfg.llm.providers)) {
      const client = createClient(name, p);
      if (client) this.clients.set(name, client);
    }
  }

  /** Returns the client configured for the given role, or the default. */
  for(role: Role | 'default' = 'default'): LLMClient {
    const providerName =
      role !== 'default' ? this.cfg.llm.roles?.[role] ?? this.cfg.llm.default : this.cfg.llm.default;
    const c = this.clients.get(providerName);
    if (!c) throw new Error(`LLM provider not configured: ${providerName}`);
    return c;
  }
}

