  const draftDir = 'docs/.draft';
  await ws.ensure(draftDir);
  const reqMd = renderRequirementsDraft(rawRequirement, clarifications);
  await ws.writeFile(`${draftDir}/requirements.md`, reqMd);

  if (!opts.yes) {
    console.log('\n' + chalk.cyan('─── requirements.md (preview) ───'));
    console.log(reqMd);
    console.log(chalk.cyan('────────────────────────────────'));
    const decision = await select({
      message: '需求是否符合预期?',
      choices: [
        { name: '✅ confirm — 进入计划生成', value: 'confirm' },
        { name: '✏️  edit    — 打开编辑器修改', value: 'edit' },
        { name: '❌ cancel  — 放弃本次会话', value: 'cancel' },
      ],
    });
    if (decision === 'cancel') {
      await ws.remove(draftDir);
      console.log(chalk.yellow('已取消，未写入任何文件。'));
      return;
    }
    if (decision === 'edit') {
      const edited = await editor({ message: '编辑需求摘要', default: reqMd, postfix: '.md' });
      await ws.writeFile(`${draftDir}/requirements.md`, edited);
    }
  }

