  const finalReqMd = await ws.readFile(`${draftDir}/requirements.md`);
  const spin2 = ora('Planner 正在按 V 模型拆解…').start();
  const draft = await planner.decompose({
    rawRequirement: finalReqMd,
    clarifications,
  });
  spin2.succeed(`已生成 ${draft.steps.length} 个 Step`);

