import { runCompile } from './compile.js';
import { runExecute } from './execute.js';

const program = new Command();
program
  .name('toaa')
  .description('TOAA — AI Software Factory CLI')
  .version('0.1.0');

program
  .command('c')
  .alias('compile')
  .description('交互式编译需求为 plan.json（含强制人工确认）')
  .option('-w, --workspace <dir>', 'workspace 目录', process.cwd())
  .option('-c, --config <file>', 'config.yaml 路径')
  .option('-i, --input <file>', '从需求文件读取（非交互）')
  .option('-o, --output <file>', '输出 plan.json 路径')
  .option('--yes', '跳过人工确认（仅在 -i 提供时有意义）', false)
  .action(async (opts) => {
    await runCompile({
      workspace: opts.workspace,
      configPath: opts.config,
      inputFile: opts.input,
      outputFile: opts.output,
      yes: !!opts.yes && !!opts.input,
    });
  });

program
  .command('run')
  .description('执行已确认的 plan.json')
  .argument('<plan>', 'plan.json 路径')
  .option('-w, --workspace <dir>', 'workspace 目录', process.cwd())
  .option('-c, --config <file>', 'config.yaml 路径')
  .option('--dry-run', '仅打印拓扑顺序，不执行', false)
  .action(async (planPath, opts) => {
    await runExecute({
      planPath,
      workspace: opts.workspace,
      configPath: opts.config,
      dryRun: !!opts.dryRun,
    });
  });

program.parseAsync(process.argv).catch((err) => {
  console.error(err?.message ?? err);
  process.exit(1);
});

