import { lintPlan, topoSort } from '../src/core/lint.js';
import { PlanSchema, type Plan } from '../src/core/plan.js';

function makePlan(overrides: Partial<Plan> = {}): Plan {
  const base: Plan = {
    version: '1',
    language: 'python',
    requirementDigest: 'todo CLI app',
    createdAt: '2026-01-01T00:00:00.000Z',
    steps: [
      {
        id: 'S001',
        phase: 'REQUIREMENT',
        title: 'collect requirements',
        description: 'd',
        role: 'Planner',
        tools: [],
        inputs: [],
        outputs: ['docs/requirements.md'],
        dependsOn: [],
        acceptance: 'requirements.md exists',
        status: 'PENDING',
        retries: 0,
        maxRetries: 3,
      },
      {
        id: 'S002',
        phase: 'ARCH',
        title: 'design architecture and deps',
        description: 'd',
        role: 'Architect',
        tools: [],
        inputs: ['docs/requirements.md'],
        outputs: ['docs/architecture.md', 'requirements.txt'],
        dependsOn: ['S001'],
        acceptance: 'arch + requirements.txt exist',
        status: 'PENDING',
        retries: 0,
        maxRetries: 3,
      },
      {
        id: 'S003',
        phase: 'CODE',
        title: 'implement core',
        description: 'd',
        role: 'Coder',
        tools: ['write_file', 'apply_patch'],
        inputs: ['docs/architecture.md'],
        outputs: ['src/app.py'],
        dependsOn: ['S002'],
        acceptance: 'src/app.py exists',
        status: 'PENDING',
        retries: 0,
        maxRetries: 3,
      },
      {
        id: 'S004',
        phase: 'TEST',
        title: 'unit test core',
        description: 'd',
        role: 'Tester',
        tools: ['run_tests'],
        inputs: ['src/app.py'],
        outputs: ['tests/test_app.py', 'docs/test_report.md'],
        dependsOn: ['S003'],
        acceptance: 'pytest passes',
        status: 'PENDING',
        retries: 0,
        maxRetries: 3,
      },
      {
        id: 'S005',
        phase: 'DELIVERY',
        title: 'package',
        description: 'd',
        role: 'Coder',
        tools: [],
        inputs: ['src/app.py'],
        outputs: ['docs/delivery.md'],
        dependsOn: ['S004'],
        acceptance: 'delivery.md exists',
        status: 'PENDING',
        retries: 0,
        maxRetries: 3,
      },
    ],
  };
  return { ...base, ...overrides };
}

describe('PlanSchema', () => {
  it('parses a valid plan', () => {
    expect(() => PlanSchema.parse(makePlan())).not.toThrow();
  });
});

describe('lintPlan', () => {
  it('passes for a well-formed plan', () => {
    expect(lintPlan(makePlan()).filter((i) => i.level === 'error')).toEqual([]);
  });

  it('detects missing requirements.txt for python', () => {
    const plan = makePlan();
    plan.steps[1]!.outputs = ['docs/architecture.md'];
    const errs = lintPlan(plan).filter((i) => i.level === 'error');
    expect(errs.some((e) => e.message.includes('requirements.txt'))).toBe(true);
  });

  it('detects CODE without TEST coverage', () => {
    const plan = makePlan();
    // remove S004 (TEST step)
    plan.steps = plan.steps.filter((s) => s.id !== 'S004');
    plan.steps[plan.steps.length - 1]!.dependsOn = ['S003'];
    const errs = lintPlan(plan).filter((i) => i.level === 'error');
    expect(errs.some((e) => e.message.includes('no corresponding TEST'))).toBe(true);
  });

  it('detects duplicate outputs', () => {
    const plan = makePlan();
    plan.steps[2]!.outputs = ['docs/requirements.md'];
    const errs = lintPlan(plan).filter((i) => i.level === 'error');
    expect(errs.some((e) => e.message.includes('already produced'))).toBe(true);
  });

  it('detects dependency cycles', () => {
    const plan = makePlan();
    plan.steps[0]!.dependsOn = ['S005'];
    const errs = lintPlan(plan).filter((i) => i.level === 'error');
    expect(errs.some((e) => e.message.includes('cycle'))).toBe(true);
  });

  it('detects phase order violation', () => {
    const plan = makePlan();
    // make REQUIREMENT depend on CODE
    plan.steps[0]!.dependsOn = ['S003'];
    const errs = lintPlan(plan).filter((i) => i.level === 'error');
    expect(errs.some((e) => e.message.includes('later phase'))).toBe(true);
  });
});

describe('topoSort', () => {
  it('orders by dependencies', () => {
    const plan = makePlan();
    const order = topoSort(plan.steps).map((s) => s.id);
    expect(order).toEqual(['S001', 'S002', 'S003', 'S004', 'S005']);
  });

  it('throws on cycle', () => {
    const plan = makePlan();
    plan.steps[0]!.dependsOn = ['S005'];
    expect(() => topoSort(plan.steps)).toThrow();
  });
});
