  name: 'list_dir',
  description: '列出指定目录下的条目（仅文件名）。',
  argsSchema: { path: 'string?' },
  async run(args, ctx) {
    try {
      const abs = ctx.ws.abs(args.path ?? '.');
      const entries = await fs.readdir(abs, { withFileTypes: true });
      return {
        ok: true,
        data: { entries: entries.map((e) => (e.isDirectory() ? e.name + '/' : e.name)) },
