      audit: this.opts.audit,
      allowedWrites: step.outputs,
      stepId: step.id,
    };
    const llm = this.opts.router.for(step.role);
    const executor =
      this.executor.get(step.role) ??
      new StepExecutor({ llm, maxRounds: this.opts.maxRoundsPerStep ?? 6 });
    this.executor.set(step.role, executor);

    // 加载 inputs 作为上下文
    const ctxSnippets: Array<{ path: string; content: string }> = [];
    for (const inp of step.inputs) {
      if (inp.endsWith('/')) continue;
      try {
        const c = await this.opts.ws.readFile(inp);
        ctxSnippets.push({ path: inp, content: c });
      } catch {
        /* ignore missing inputs */
      }
    }

    step.status = 'RUNNING';
    await savePlan(this.opts.planPath, plan);
    const sha = await this.opts.git.snapshot(step.id, step.retries, `before ${step.phase}`);
    await this.opts.audit.event('phase.start', `${step.id} ${step.phase} ${step.title}`, {
      role: step.role,
      tools: step.tools,
      snapshot: sha,
    });

    const spin = ora(`▶ ${step.id} ${step.phase} ${chalk.bold(step.title)}`).start();
    try {
      const r = await executor.run({ step, tools, ctx, contextSnippets: ctxSnippets });
      const verify = await verifyOutputs({ step, tools, ctx });
      if (r.success && verify.ok) {
        step.status = 'DONE';
        await this.opts.git.snapshot(step.id, step.retries, `done ${step.phase}`);
        spin.succeed(`${step.id} DONE (rounds=${r.rounds})`);
        await this.opts.audit.event('phase.end', `${step.id} DONE`, { rounds: r.rounds });
        return true;
      }
      step.status = 'FAILED';
      const reason = r.error ?? `outputs missing: ${verify.missing.join(', ')}`;
      spin.fail(`${step.id} FAILED — ${reason}`);
      await this.opts.audit.event('phase.end', `${step.id} FAILED`, {
        rounds: r.rounds,
        reason,
        toolCalls: r.toolCalls,
      });
      // 失败回退到 step 起点
      await this.opts.git.revertTo(sha);
      return false;
    } catch (err) {
      step.status = 'FAILED';
      const msg = (err as Error).message;
      spin.fail(`${step.id} FAILED — ${msg}`);
      await this.opts.audit.event('phase.end', `${step.id} FAILED (exception)`, { error: msg });
      await this.opts.git.revertTo(sha).catch(() => {});
      return false;
    } finally {
      // 失败时进度条已 fail，状态已写
      void path; // silence unused import (path is exported via index of node only)
    }
  }
}

