  });

  it('宿主上 sandbox=docker 正常实例化（不抛错）', () => {
    process.env.TOAA_IN_CONTAINER = '0';
    const ws = new Workspace('/tmp/toaa-factory-test');
    expect(() => createSandbox(baseCfg('docker'), ws)).not.toThrow();
  });
});
