import type { ToaaConfig } from '../src/config/config.js';

const baseCfg = (sandbox: 'subprocess' | 'docker'): ToaaConfig =>
  ({
    llm: { default: 'ollama_code', providers: {}, roles: {}, fallbacks: [] },
