async function resolveWorkspace(opts: { workspace?: string; baseDir?: string; name?: string }): Promise<string> {
  if (opts.workspace) return path.resolve(opts.workspace);
  const base = opts.baseDir ? path.resolve(opts.baseDir) : '/tmp';
  const name = opts.name ?? defaultProjectName();
  const ws = path.join(base, name);
  await fs.mkdir(ws, { recursive: true });
  return ws;
}

replacements.newString:
async function resolveWorkspace(opts: {
  output?: string;
  workspace?: string;
  baseDir?: string;
  name?: string;
}): Promise<string> {
  // 优先级：--output > --workspace > <base-dir>/<name>
  const explicit = opts.output ?? opts.workspace;
  if (explicit) {
    const ws = path.resolve(explicit);
    await fs.mkdir(ws, { recursive: true });
    return ws;
  }
  const base = opts.baseDir ? path.resolve(opts.baseDir) : '/tmp';
  const name = opts.name ?? defaultProjectName();
  const ws = path.join(base, name);
  await fs.mkdir(ws, { recursive: true });
  return ws;
}

